import { Link, useNavigate } from "@tanstack/react-router";

import { ErrorMessage, useAppForm } from "@/components/ui/form";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { centralAuthClient } from "@/services/auth/client/central";
import { m } from "@/paraglide/messages";

export function SignIn() {
  const navigate = useNavigate();
  const form = useAppForm({
    defaultValues: {
      email: "",
      password: "",
    },
    onSubmit: async ({ value, formApi }) => {
      formApi.setErrorMap({});

      const result = await centralAuthClient.signIn.email({
        email: value.email,
        password: value.password,
      });

      if (result.error) {
        formApi.setErrorMap({
          onSubmit: {
            form: result.error.message ?? m.sign_in_error(),
            fields: {},
          },
        });
        return;
      }

      navigate({ href: result.data?.url ?? "/" });
    },
  });

  return (
    <Card className="w-full max-w-md">
      <CardHeader>
        <CardTitle className="text-3xl">{m.auth_sign_in()}</CardTitle>
        <CardDescription>{m.sign_in_description()}</CardDescription>
      </CardHeader>
      <CardContent>
        <form.AppForm>
          <form
            className="flex flex-col gap-4"
            onSubmit={(event) => {
              event.preventDefault();
              event.stopPropagation();
              form.handleSubmit();
            }}
          >
            <form.AppField name="email">
              {(field) => (
                <field.TextField
                  label={m.field_email()}
                  type="email"
                  autoComplete="email"
                  required
                />
              )}
            </form.AppField>
            <form.AppField name="password">
              {(field) => (
                <field.TextField
                  label={m.field_password()}
                  type="password"
                  autoComplete="current-password"
                  required
                />
              )}
            </form.AppField>
            <form.Subscribe
              selector={(formState) =>
                (formState.errorMap.onSubmit as { form?: unknown } | undefined)
                  ?.form
              }
            >
              {(error) =>
                error ? <ErrorMessage text={String(error)} /> : null
              }
            </form.Subscribe>
            <form.SubmitButton />
          </form>
        </form.AppForm>
        <p className="text-muted-foreground mt-6 text-center text-sm">
          {m.sign_in_need_account()}{" "}
          <Link
            className="text-foreground font-medium underline-offset-4 hover:underline"
            to="/sign-up"
          >
            {m.auth_sign_up()}
          </Link>
        </p>
      </CardContent>
    </Card>
  );
}

import { apiKeyClient } from "@better-auth/api-key/client";
import { createAuthClient } from "better-auth/react";
import {
  organizationClient,
  twoFactorClient,
} from "better-auth/client/plugins";

export const centralAuthUrl = (path: string) =>
  new URL(path, import.meta.env.VITE_KRAKSTACK_AUTH_URL).toString();

export const centralLoginUrl = (
  callbackURL: string,
  locale: "en" | "fr" = "en",
) => {
  const url = new URL(
    `/${locale}/sign-in`,
    import.meta.env.VITE_KRAKSTACK_AUTH_URL,
  );
  url.searchParams.set("redirect", callbackURL);
  return url.toString();
};

export const centralAuthClient = createAuthClient({
  baseURL: import.meta.env.VITE_KRAKSTACK_AUTH_URL,
  fetchOptions: {
    credentials: "include",
  },
  plugins: [
    twoFactorClient({
      twoFactorPage: `${import.meta.env.VITE_KRAKSTACK_AUTH_URL}/2fa`,
    }),
    organizationClient(),
    apiKeyClient(),
  ],
});
